import com.ecommerce.search.model.Product;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.elasticsearch.action.search.SearchRequestBuilder;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.text.Text;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.filter.Filter;
import org.elasticsearch.search.aggregations.bucket.histogram.Histogram;
import org.elasticsearch.search.aggregations.bucket.range.Range;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.aggregations.metrics.Avg;
import org.elasticsearch.search.aggregations.metrics.Stats;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.fetch.subphase.highlight.HighlightBuilder;
import org.elasticsearch.search.fetch.subphase.highlight.HighlightField;
import org.elasticsearch.search.sort.SortOrder;
import org.elasticsearch.search.suggest.SuggestBuilder;
import org.elasticsearch.search.suggest.SuggestBuilders;
import org.elasticsearch.search.suggest.completion.CompletionSuggestion;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.IOException;
import java.util.*;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Slf4j
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final SearchQueryService searchQueryService;
    private ObjectMapper objectMapper;

    private static final String INDEX = IndexManagementService.PRODUCT_INDEX;

    @PostConstruct
    public void init() {
        objectMapper = new ObjectMapper();
        objectMapper.registerModule(new JavaTimeModule());
    }

    public SearchResponse search(SearchRequest searchRequest) throws IOException {
        long startTime = System.currentTimeMillis();

        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = buildQuery(searchRequest);
        sourceBuilder.query(boolQuery);

        int page = searchRequest.getPageOrDefault();
        int size = searchRequest.getSizeOrDefault();
        sourceBuilder.from(page * size);
        sourceBuilder.size(size);

        addSorting(sourceBuilder, searchRequest);
        addHighlighting(sourceBuilder);
        addAggregations(sourceBuilder);

        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse esResponse =
                client.search(esRequest, RequestOptions.DEFAULT);

        long responseTime = System.currentTimeMillis() - startTime;

        List<Product> products = parseProducts(esResponse);
        Map<String, List<FacetBucket>> facets = parseFacets(esResponse);

        SearchResponse response = SearchResponse.builder()
                .products(products)
                .totalHits(esResponse.getHits().getTotalHits().value)
                .page(page)
                .size(size)
                .totalPages((int) Math.ceil((double) esResponse.getHits().getTotalHits().value / size))
                .responseTimeMs(responseTime)
                .facets(facets)
                .build();

        searchQueryService.logSearchQuery(searchRequest, response);

        return response;
    }

    private BoolQueryBuilder buildQuery(SearchRequest request) {
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        // Only show active products
        boolQuery.filter(QueryBuilders.termQuery("active", true));

        // Full-text search
        if (request.getQuery() != null && !request.getQuery().trim().isEmpty()) {
            MultiMatchQueryBuilder multiMatch = QueryBuilders.multiMatchQuery(request.getQuery(),
                            "name^3", "description^1", "brand^2", "category^2", "tags^1.5")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .fuzziness("AUTO")
                    .minimumShouldMatch("75%");

            boolQuery.must(multiMatch);

            // Boost exact matches
            boolQuery.should(QueryBuilders.matchPhraseQuery("name", request.getQuery()).boost(5.0f));
            boolQuery.should(QueryBuilders.matchPhraseQuery("description", request.getQuery()).boost(2.0f));
        }

        // Price range filter
        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            var rangeQuery = QueryBuilders.rangeQuery("price");
            if (request.getMinPrice() != null) {
                rangeQuery.gte(request.getMinPrice().doubleValue());
            }
            if (request.getMaxPrice() != null) {
                rangeQuery.lte(request.getMaxPrice().doubleValue());
            }
            boolQuery.filter(rangeQuery);
        }

        // Brand filter
        if (request.getBrands() != null && !request.getBrands().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("brand.keyword", request.getBrands()));
        }

        // Category filter
        if (request.getCategories() != null && !request.getCategories().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("categories", request.getCategories()));
        }

        // Rating filter
        if (request.getMinRating() != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("rating").gte(request.getMinRating()));
        }

        // In stock filter
        if (request.getInStock() != null && request.getInStock()) {
            boolQuery.filter(QueryBuilders.termQuery("inStock", true));
        }

        // Dynamic attribute filters
        if (request.getAttributes() != null && !request.getAttributes().isEmpty()) {
            for (Map.Entry<String, String> entry : request.getAttributes().entrySet()) {
                boolQuery.filter(QueryBuilders.termQuery("attributes." + entry.getKey(), entry.getValue()));
            }
        }

        return boolQuery;
    }

    private void addSorting(SearchSourceBuilder sourceBuilder, SearchRequest request) {
        if (request.getSortField() != null && !request.getSortField().isEmpty()) {
            SortOrder order = "desc".equalsIgnoreCase(request.getSortOrder()) ?
                    SortOrder.DESC : SortOrder.ASC;

            switch (request.getSortField().toLowerCase()) {
                case "price":
                    sourceBuilder.sort("price", order);
                    break;
                case "rating":
                    sourceBuilder.sort("rating", order);
                    break;
                case "name":
                    sourceBuilder.sort("name.keyword", order);
                    break;
                case "newest":
                    sourceBuilder.sort("createdAt", SortOrder.DESC);
                    break;
                case "popularity":
                    sourceBuilder.sort("reviewCount", SortOrder.DESC);
                    break;
                default:
                    sourceBuilder.sort("_score", SortOrder.DESC);
            }
        } else {
            sourceBuilder.sort("_score", SortOrder.DESC);
        }
    }

    private void addHighlighting(SearchSourceBuilder sourceBuilder) {
        HighlightBuilder highlightBuilder = new HighlightBuilder();
        highlightBuilder.field("name").preTags("<em>").postTags("</em>");
        highlightBuilder.field("description").preTags("<em>").postTags("</em>")
                .fragmentSize(150).numOfFragments(3);
        sourceBuilder.highlighter(highlightBuilder);
    }

    private void addAggregations(SearchSourceBuilder sourceBuilder) {
        // Brand facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("brands")
                        .field("brand.keyword")
                        .size(50)
        );

        // Category facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("categories")
                        .field("categories")
                        .size(50)
        );

        // Price range facet
        sourceBuilder.aggregation(
                AggregationBuilders.range("price_ranges")
                        .field("price")
                        .addUnboundedTo("Under $25", 25)
                        .addRange("$25 - $50", 25, 50)
                        .addRange("$50 - $100", 50, 100)
                        .addRange("$100 - $200", 100, 200)
                        .addRange("$200 - $500", 200, 500)
                        .addUnboundedFrom("$500+", 500)
        );

        // Rating facet
        sourceBuilder.aggregation(
                AggregationBuilders.range("ratings")
                        .field("rating")
                        .addRange("4+ Stars", 4, 5.01)
                        .addRange("3+ Stars", 3, 5.01)
                        .addRange("2+ Stars", 2, 5.01)
                        .addRange("1+ Stars", 1, 5.01)
        );

        // Price statistics
        sourceBuilder.aggregation(
                AggregationBuilders.stats("price_stats")
                        .field("price")
        );

        // Average rating
        sourceBuilder.aggregation(
                AggregationBuilders.avg("avg_rating")
                        .field("rating")
        );

        // Tags facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("tags")
                        .field("tags")
                        .size(30)
        );

        // Seller facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("sellers")
                        .field("seller")
                        .size(20)
        );

        // In stock count
        sourceBuilder.aggregation(
                AggregationBuilders.filter("in_stock_count",
                        QueryBuilders.termQuery("inStock", true))
        );
    }

    private List<Product> parseProducts(org.elasticsearch.action.search.SearchResponse response) {
        List<Product> products = new ArrayList<>();

        for (SearchHit hit : response.getHits().getHits()) {
            Product product = objectMapper.convertValue(hit.getSourceAsMap(), Product.class);
            product.setId(hit.getId());

            // Apply highlights
            Map<String, HighlightField> highlights = hit.getHighlightFields();
            if (highlights.containsKey("name")) {
                String highlightedName = Arrays.stream(highlights.get("name").fragments())
                        .map(Text::string)
                        .collect(Collectors.joining(" "));
                // You could store highlighted text separately if needed
            }

            products.add(product);
        }

        return products;
    }

    private Map<String, List<FacetBucket>> parseFacets(
            org.elasticsearch.action.search.SearchResponse response) {

        Map<String, List<FacetBucket>> facets = new LinkedHashMap<>();

        if (response.getAggregations() == null) {
            return facets;
        }

        // Brand facet
        Terms brandTerms = response.getAggregations().get("brands");
        if (brandTerms != null) {
            facets.put("brands", brandTerms.getBuckets().stream()
                    .map(b -> FacetBucket.builder()
                            .key(b.getKeyAsString())
                            .count(b.getDocCount())
                            .build())
                    .collect(Collectors.toList()));
        }

        // Category facet
        Terms categoryTerms = response.getAggregations().get("categories");
        if (categoryTerms != null) {
            facets.put("categories", categoryTerms.getBuckets().stream()
                    .map(b -> FacetBucket.builder()
                            .key(b.getKeyAsString())
                            .count(b.getDocCount())
                            .build())
                    .collect(Collectors.toList()));
        }

        // Price ranges facet
        Range priceRanges = response.getAggregations().get("price_ranges");
        if (priceRanges != null) {
            facets.put("price_ranges", priceRanges.getBuckets().stream()
                    .filter(b -> b.getDocCount() > 0)
                    .map(b -> FacetBucket.builder()
                            .key(b.getKeyAsString())
                            .count(b.getDocCount())
                            .build())
                    .collect(Collectors.toList()));
        }

        // Rating ranges facet
        Range ratingRanges = response.getAggregations().get("ratings");
        if (ratingRanges != null) {
            facets.put("ratings", ratingRanges.getBuckets().stream()
                    .filter(b -> b.getDocCount() > 0)
                    .map(b -> FacetBucket.builder()
                            .key(b.getKeyAsString())
                            .count(b.getDocCount())
                            .build())
                    .collect(Collectors.toList()));
        }

        // Tags facet
        Terms tagTerms = response.getAggregations().get("tags");
        if (tagTerms != null) {
            facets.put("tags", tagTerms.getBuckets().stream()
                    .map(b -> FacetBucket.builder()
                            .key(b.getKeyAsString())
                            .count(b.getDocCount())
                            .build())
                    .collect(Collectors.toList()));
        }

        // Sellers facet
        Terms sellerTerms = response.getAggregations().get("sellers");
        if (sellerTerms != null) {
            facets.put("sellers", sellerTerms.getBuckets().stream()
                    .map(b -> FacetBucket.builder()
                            .key(b.getKeyAsString())
                            .count(b.getDocCount())
                            .build())
                    .collect(Collectors.toList()));
        }

        // Price stats
        Stats priceStats = response.getAggregations().get("price_stats");
        if (priceStats != null && priceStats.getCount() > 0) {
            List<FacetBucket> statsBuckets = new ArrayList<>();
            statsBuckets.add(FacetBucket.builder().key("min_price: " + priceStats.getMin()).count(0).build());
            statsBuckets.add(FacetBucket.builder().key("max_price: " + priceStats.getMax()).count(0).build());
            statsBuckets.add(FacetBucket.builder().key("avg_price: " + priceStats.getAvg()).count(priceStats.getCount()).build());
            facets.put("price_stats", statsBuckets);
        }

        // In stock count
        Filter inStockFilter = response.getAggregations().get("in_stock_count");
        if (inStockFilter != null) {
            facets.put("in_stock", List.of(
                    FacetBucket.builder().key("in_stock").count(inStockFilter.getDocCount()).build()
            ));
        }

        return facets;
    }

    public AutocompleteResponse autocomplete(String prefix) throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        SuggestBuilder suggestBuilder = new SuggestBuilder();
        suggestBuilder.addSuggestion("product_suggest",
                SuggestBuilders.completionSuggestion("name.suggest")
                        .prefix(prefix)
                        .size(10)
                        .skipDuplicates(true));

        sourceBuilder.suggest(suggestBuilder);

        // Also add term-based aggregations for brands and categories matching prefix
        BoolQueryBuilder prefixQuery = QueryBuilders.boolQuery()
                .should(QueryBuilders.prefixQuery("name.keyword", prefix))
                .should(QueryBuilders.matchPhrasePrefixQuery("name", prefix))
                .should(QueryBuilders.prefixQuery("brand.keyword", prefix))
                .should(QueryBuilders.prefixQuery("categories", prefix))
                .filter(QueryBuilders.termQuery("active", true));

        SearchSourceBuilder auxSourceBuilder = new SearchSourceBuilder();
        auxSourceBuilder.query(prefixQuery);
        auxSourceBuilder.size(5);
        auxSourceBuilder.aggregation(AggregationBuilders.terms("brand_suggestions")
                .field("brand.keyword").size(5));
        auxSourceBuilder.aggregation(AggregationBuilders.terms("category_suggestions")
                .field("categories").size(5));

        org.elasticsearch.action.search.SearchRequest auxRequest =
                new org.elasticsearch.action.search.SearchRequest(INDEX);
        auxRequest.source(auxSourceBuilder);

        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse suggestResponse =
                client.search(esRequest, RequestOptions.DEFAULT);
        org.elasticsearch.action.search.SearchResponse auxResponse =
                client.search(auxRequest, RequestOptions.DEFAULT);

        List<String> suggestions = new ArrayList<>();
        if (suggestResponse.getSuggest() != null) {
            CompletionSuggestion completionSuggestion =
                    suggestResponse.getSuggest().getSuggestion("product_suggest");
            if (completionSuggestion != null) {
                for (CompletionSuggestion.Entry entry : completionSuggestion.getEntries()) {
                    for (CompletionSuggestion.Entry.Option option : entry.getOptions()) {
                        suggestions.add(option.getText().string());
                    }
                }
            }
        }

        List<String> productNames = new ArrayList<>();
        for (SearchHit hit : auxResponse.getHits().getHits()) {
            Map<String, Object> source = hit.getSourceAsMap();
            if (source.containsKey("name")) {
                productNames.add(source.get("name").toString());
            }
        }

        List<String> brands = new ArrayList<>();
        List<String> categories = new ArrayList<>();

        if (auxResponse.getAggregations() != null) {
            Terms brandTerms = auxResponse.getAggregations().get("brand_suggestions");
            if (brandTerms != null) {
                brands = brandTerms.getBuckets().stream()
                        .map(b -> b.getKeyAsString())
                        .collect(Collectors.toList());
            }

            Terms catTerms = auxResponse.getAggregations().get("category_suggestions");
            if (catTerms != null) {
                categories = catTerms.getBuckets().stream()
                        .map(b -> b.getKeyAsString())
                        .collect(Collectors.toList());
            }
        }

        return AutocompleteResponse.builder()
                .suggestions(suggestions)
                .productNames(productNames)
                .brands(brands)
                .categories(categories)
                .build();
    }

    public List<Product> findSimilarProducts(String productId, int size) throws IOException {
        Product product = getProductById(productId);
        if (product == null) {
            return Collections.emptyList();
        }

        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();
        boolQuery.mustNot(QueryBuilders.termQuery("_id", productId));
        boolQuery.filter(QueryBuilders.termQuery("active", true));

        // Match by category and brand with boosting
        if (product.getCategory() != null) {
            boolQuery.should(QueryBuilders.matchQuery("category", product.getCategory()).boost(3.0f));
        }
        if (product.getBrand() != null) {
            boolQuery.should(QueryBuilders.matchQuery("brand", product.getBrand()).boost(2.0f));
        }
        if (product.getTags() != null && !product.getTags().isEmpty()) {
            boolQuery.should(QueryBuilders.termsQuery("tags", product.getTags()).boost(1.5f));
        }
        // Similar price range
        if (product.getPrice() != null) {
            double minPrice = product.getPrice().doubleValue() * 0.5;
            double maxPrice = product.getPrice().doubleValue() * 1.5;
            boolQuery.should(QueryBuilders.rangeQuery("price").gte(minPrice).lte(maxPrice));
        }

        // More like this
        boolQuery.should(QueryBuilders.moreLikeThisQuery(
                        new String[]{"name", "description"},
                        new String[]{product.getName() + " " + product.getDescription()},
                        null)
                .minTermFreq(1)
                .minDocFreq(1)
                .boost(2.0f));

        sourceBuilder.query(boolQuery);
        sourceBuilder.size(size);

        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse response =
                client.search(esRequest, RequestOptions.DEFAULT);

        return parseProducts(response);
    }

    private Product getProductById(String id) throws IOException {
        org.elasticsearch.action.get.GetRequest request =
                new org.elasticsearch.action.get.GetRequest(INDEX, id);
        org.elasticsearch.action.get.GetResponse response =
                client.get(request, RequestOptions.DEFAULT);

        if (response.isExists()) {
            Product product = objectMapper.convertValue(response.getSourceAsMap(), Product.class);
            product.setId(response.getId());
            return product;
        }
        return null;
    }
}

