package com.ecommerce.search.service;

import com.ecommerce.search.dto.SearchRequest;
import com.ecommerce.search.dto.SearchResponse;
import com.ecommerce.search.model.SearchQuery;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequestBuilder;
import org.elasticsearch.action.update.UpdateRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.IOException;
import java.time.LocalDateTime;
import java.util.*;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Slf4j
public class SearchQueryService {

    private final RestHighLevelClient client;
    private ObjectMapper objectMapper;

    private static final String INDEX = IndexManagementService.SEARCH_QUERY_INDEX;

    @PostConstruct
    public void init() {
        objectMapper = new ObjectMapper();
        objectMapper.registerModule(new JavaTimeModule());
    }

    @Async
    public void logSearchQuery(SearchRequest request, SearchResponse response) {
        try {
            SearchQuery searchQuery = SearchQuery.builder()
                    .id(UUID.randomUUID().toString())
                    .queryText(request.getQuery())
                    .userId(request.getUserId())
                    .sessionId(request.getSessionId())
                    .resultsCount((int) response.getTotalHits())
                    .responseTimeMs(response.getResponseTimeMs())
                    .timestamp(LocalDateTime.now())
                    .clickedResult(false)
                    .build();

            Map<String, String> filters = new HashMap<>();
            if (request.getBrands() != null && !request.getBrands().isEmpty()) {
                filters.put("brands", String.join(",", request.getBrands()));
            }
            if (request.getCategories() != null && !request.getCategories().isEmpty()) {
                filters.put("categories", String.join(",", request.getCategories()));
            }
            if (request.getMinPrice() != null) {
                filters.put("minPrice", request.getMinPrice().toString());
            }
            if (request.getMaxPrice() != null) {
                filters.put("maxPrice", request.getMaxPrice().toString());
            }
            if (request.getMinRating() != null) {
                filters.put("minRating", request.getMinRating().toString());
            }
            searchQuery.setFilters(filters);

            Map<String, Object> queryMap = objectMapper.convertValue(searchQuery, Map.class);

            IndexRequest indexRequest = new IndexRequest(INDEX)
                    .id(searchQuery.getId())
                    .source(queryMap, XContentType.JSON);

            client.index(indexRequest, RequestOptions.DEFAULT);
            log.debug("Search query logged: {}", searchQuery.getQueryText());
        } catch (Exception e) {
            log.error("Failed to log search query", e);
        }
    }

    public void logSearchClick(String searchQueryId, String productId) throws IOException {
        UpdateRequest updateRequest = new UpdateRequest(INDEX, searchQueryId)
                .doc("clickedResult", true,
                        "clickedProductId", productId);

        client.update(updateRequest, RequestOptions.DEFAULT);
        log.debug("Search click logged: queryId={}, productId={}", searchQueryId, productId);
    }

    public List<String> getPopularSearches(int size) throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        // Only queries from last 7 days
        sourceBuilder.query(QueryBuilders.rangeQuery("timestamp")
                .gte("now-7d/d"));

        sourceBuilder.aggregation(
                AggregationBuilders.terms("popular_queries")
                        .field("queryText.keyword")
                        .size(size)
                        .minDocCount(2)
        );

        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse response =
                client.search(esRequest, RequestOptions.DEFAULT);

        Terms terms = response.getAggregations().get("popular_queries");
        return terms.getBuckets().stream()
                .map(b -> b.getKeyAsString())
                .collect(Collectors.toList());
    }

    public List<String> getTrendingSearches(int size) throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        // Only queries from last 24 hours
        sourceBuilder.query(QueryBuilders.rangeQuery("timestamp")
                .gte("now-1d/d"));

        sourceBuilder.aggregation(
                AggregationBuilders.terms("trending_queries")
                        .field("queryText.keyword")
                        .size(size)
                        .minDocCount(1)
        );

        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse response =
                client.search(esRequest, RequestOptions.DEFAULT);

        Terms terms = response.getAggregations().get("trending_queries");
        return terms.getBuckets().stream()
                .map(b -> b.getKeyAsString())
                .collect(Collectors.toList());
    }

    public Map<String, Object> getSearchAnalytics(String startDate, String endDate) throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        sourceBuilder.query(QueryBuilders.rangeQuery("timestamp")
                .gte(startDate)
                .lte(endDate));

        sourceBuilder.aggregation(
                AggregationBuilders.terms("top_queries")
                        .field("queryText.keyword")
                        .size(20));

        sourceBuilder.aggregation(
                AggregationBuilders.avg("avg_response_time")
                        .field("responseTimeMs"));

        sourceBuilder.aggregation(
                AggregationBuilders.avg("avg_results")
                        .field("resultsCount"));

        sourceBuilder.aggregation(
                AggregationBuilders.filter("zero_results",
                        QueryBuilders.termQuery("resultsCount", 0)));

        sourceBuilder.aggregation(
                AggregationBuilders.filter("clicked_results",
                        QueryBuilders.termQuery("clickedResult", true)));

        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse response =
                client.search(esRequest, RequestOptions.DEFAULT);

        Map<String, Object> analytics = new LinkedHashMap<>();
        analytics.put("totalSearches", response.getHits().getTotalHits().value);

        Terms topQueries = response.getAggregations().get("top_queries");
        analytics.put("topQueries", topQueries.getBuckets().stream()
                .map(b -> Map.of("query", b.getKeyAsString(), "count", b.getDocCount()))
                .collect(Collectors.toList()));

        org.elasticsearch.search.aggregations.metrics.Avg avgTime =
                response.getAggregations().get("avg_response_time");
        analytics.put("avgResponseTimeMs", avgTime.getValue());

        org.elasticsearch.search.aggregations.metrics.Avg avgResults =
                response.getAggregations().get("avg_results");
        analytics.put("avgResultsCount", avgResults.getValue());

        org.elasticsearch.search.aggregations.bucket.filter.Filter zeroResults =
                response.getAggregations().get("zero_results");
        analytics.put("zeroResultSearches", zeroResults.getDocCount());

        org.elasticsearch.search.aggregations.bucket.filter.Filter clickedResults =
                response.getAggregations().get("clicked_results");
        analytics.put("searchesWithClicks", clickedResults.getDocCount());

        long totalSearches = response.getHits().getTotalHits().value;
        if (totalSearches > 0) {
            analytics.put("clickThroughRate",
                    (double) clickedResults.getDocCount() / totalSearches * 100);
            analytics.put("zeroResultRate",
                    (double) zeroResults.getDocCount() / totalSearches * 100);
        }

        return analytics;
    }

    public List<SearchQuery> getUserSearchHistory(String userId, int size) throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.query(QueryBuilders.termQuery("userId", userId));
        sourceBuilder.sort("timestamp", SortOrder.DESC);
        sourceBuilder.size(size);

        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse response =
                client.search(esRequest, RequestOptions.DEFAULT);

        List<SearchQuery> queries = new ArrayList<>();
        for (org.elasticsearch.search.SearchHit hit : response.getHits().getHits()) {
            SearchQuery query = objectMapper.convertValue(hit.getSourceAsMap(), SearchQuery.class);
            query.setId(hit.getId());
            queries.add(query);
        }

        return queries;
    }
}

