package com.ecommerce.search.controller;

import com.ecommerce.search.model.Product;
import com.ecommerce.search.service.ProductIndexService;
import lombok.RequiredArgsConstructor;
import org.elasticsearch.action.bulk.BulkResponse;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/products")
@RequiredArgsConstructor
public class ProductController {

    private final ProductIndexService productIndexService;

    @PostMapping
    public ResponseEntity<Map<String, String>> indexProduct(@RequestBody Product product) throws IOException {
        String id = productIndexService.indexProduct(product);
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(Map.of("id", id, "message", "Product indexed successfully"));
    }

    @PostMapping("/bulk")
    public ResponseEntity<Map<String, Object>> bulkIndexProducts(@RequestBody List<Product> products) throws IOException {
        BulkResponse response = productIndexService.bulkIndexProducts(products);
        return ResponseEntity.ok(Map.of(
                "indexed", products.size(),
                "hasFailures", response.hasFailures(),
                "message", response.hasFailures() ?
                        "Some products failed to index: " + response.buildFailureMessage() :
                        "All products indexed successfully"
        ));
    }

    @GetMapping("/{id}")
    public ResponseEntity<Product> getProduct(@PathVariable String id) throws IOException {
        Product product = productIndexService.getProduct(id);
        if (product != null) {
            return ResponseEntity.ok(product);
        }
        return ResponseEntity.notFound().build();
    }

    @PutMapping("/{id}")
    public ResponseEntity<Map<String, String>> updateProduct(
            @PathVariable String id, @RequestBody Product product) throws IOException {
        productIndexService.updateProduct(id, product);
        return ResponseEntity.ok(Map.of("id", id, "message", "Product updated successfully"));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Map<String, String>> deleteProduct(@PathVariable String id) throws IOException {
        productIndexService.deleteProduct(id);
        return ResponseEntity.ok(Map.of("id", id, "message", "Product deleted successfully"));
    }

    @PatchMapping("/{id}/stock")
    public ResponseEntity<Map<String, String>> updateStock(
            @PathVariable String id, @RequestParam int quantity) throws IOException {
        productIndexService.updateStock(id, quantity);
        return ResponseEntity.ok(Map.of("id", id, "message", "Stock updated successfully"));
    }
}

