package com.ecommerce.search.controller;

import com.ecommerce.search.dto.AutocompleteResponse;
import com.ecommerce.search.dto.SearchRequest;
import com.ecommerce.search.dto.SearchResponse;
import com.ecommerce.search.model.Product;
import com.ecommerce.search.service.ProductSearchService;
import lombok.RequiredArgsConstructor;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.List;

@RestController
@RequestMapping("/api/search")
@RequiredArgsConstructor
public class SearchController {

    private final ProductSearchService productSearchService;

    @PostMapping
    public ResponseEntity<SearchResponse> search(@RequestBody SearchRequest searchRequest) throws IOException {
        SearchResponse response = productSearchService.search(searchRequest);
        return ResponseEntity.ok(response);
    }

    @GetMapping
    public ResponseEntity<SearchResponse> searchGet(
            @RequestParam(required = false) String query,
            @RequestParam(required = false, defaultValue = "0") Integer page,
            @RequestParam(required = false, defaultValue = "20") Integer size,
            @RequestParam(required = false) String sortField,
            @RequestParam(required = false) String sortOrder,
            @RequestParam(required = false) Double minPrice,
            @RequestParam(required = false) Double maxPrice,
            @RequestParam(required = false) List<String> brands,
            @RequestParam(required = false) List<String> categories,
            @RequestParam(required = false) Double minRating,
            @RequestParam(required = false) Boolean inStock,
            @RequestParam(required = false) String userId,
            @RequestParam(required = false) String sessionId) throws IOException {

        SearchRequest searchRequest = SearchRequest.builder()
                .query(query)
                .page(page)
                .size(size)
                .sortField(sortField)
                .sortOrder(sortOrder)
                .minPrice(minPrice != null ? java.math.BigDecimal.valueOf(minPrice) : null)
                .maxPrice(maxPrice != null ? java.math.BigDecimal.valueOf(maxPrice) : null)
                .brands(brands)
                .categories(categories)
                .minRating(minRating)
                .inStock(inStock)
                .userId(userId)
                .sessionId(sessionId)
                .build();

        SearchResponse response = productSearchService.search(searchRequest);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/autocomplete")
    public ResponseEntity<AutocompleteResponse> autocomplete(@RequestParam String prefix) throws IOException {
        AutocompleteResponse response = productSearchService.autocomplete(prefix);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/similar/{productId}")
    public ResponseEntity<List<Product>> similarProducts(
            @PathVariable String productId,
            @RequestParam(defaultValue = "10") int size) throws IOException {
        List<Product> products = productSearchService.findSimilarProducts(productId, size);
        return ResponseEntity.ok(products);
    }
}

